// Transactional booking handler — prevents double bookings via row-level locking
async function createBooking(
  userId: string,
  propertyId: string,
  date: Date
): Promise<{ status: number; body: any }> {
  const client = await pool.connect();

  try {
    // BEGIN SERIALIZABLE transaction — strongest isolation level
    await client.query('BEGIN ISOLATION LEVEL SERIALIZABLE');

    // Lock the date range for this property
    // SELECT FOR UPDATE blocks concurrent writers on the same rows
    const { rowCount } = await client.query(
      `SELECT 1 FROM availability
       WHERE property_id = $1
         AND date = $2
         AND status = 'available'
       FOR UPDATE`,
      [propertyId, date]
    );

    // If no rows matched, the slot is already taken
    if (rowCount === 0) {
      await client.query('ROLLBACK');
      return {
        status: 409,
        body: { error: 'This time slot is no longer available' }
      };
    }

    // We hold the lock — safe to insert
    await client.query(
      `INSERT INTO bookings (user_id, property_id, date, status)
       VALUES ($1, $2, $3, 'confirmed')`,
      [userId, propertyId, date]
    );

    await client.query('COMMIT');

    return {
      status: 200,
      body: { bookingId: bookingId, status: 'confirmed' }
    };
  } catch (err) {
    await client.query('ROLLBACK');

    // 40001 = serialization failure — retry with exponential backoff
    if (err.code === '40001' && retryCount < 3) {
      const delay = Math.pow(2, retryCount) * 50 + Math.random() * 50;
      await new Promise(r => setTimeout(r, delay));
      return createBooking(userId, propertyId, date, retryCount + 1);
    }

    throw err;
  } finally {
    client.release();
  }
}
